    window.setMode=m=>{$('shell-v9').className='theme-'+m;document.querySelectorAll('.t-btn').forEach(b=>{b.classList.remove('active');if(b.innerText.includes(m==='day'?'☀':m==='night'?'🌙':'📜'))b.classList.add('active')})};

