<script>
(function(){
    const getVal = (id) => document.getElementById(id) ? document.getElementById(id).innerText : "";

    // 1. Khởi tạo cơ bản
    document.getElementById('ui-now-loc').innerText = getVal('d-loc');
    document.getElementById('ui-time').innerText = getVal('d-time');

    // 2. Phân tích dữ liệu lưới
    const rawGrid = getVal('d-grid').split('#');
    const gridBox = document.getElementById('ui-grid-box');

    const zoneDataMap = [];

    // Render lưới
    let htmlLines = "";
    rawGrid.forEach((str, idx) => {
        const p = str.split('|');
        const data = {
            id: idx,
            name: p[0] || "Chưa rõ",
            status: p[1] || "locked",
            weather: p[2] || "Chưa biết",
            crowd: p[3] || "Chưa biết",
            facility: p[4] || "???",
            trend: p[5] || "???",
            rare: p[6] || "Không"
        };
        zoneDataMap.push(data);

        let cls = "zone";
        if(data.status === 'element') cls += " locked";
        if(data.status === 'locked') cls += " locked";
        if(data.status === 'current') cls += " current";

        htmlLines += `
        <div class="${cls}" onclick="window.clickZone(${idx})">
            <span class="zone-name">${data.name.replace("Khu","Khu<br>")}</span>
        </div>`;
    });

    for(let i=zoneDataMap.length; i<9; i++){
        htmlLines += `<div class="zone locked"><span class="zone-name">🔒</span></div>`;
    }
    gridBox.innerHTML = htmlLines;

    // 3. Logic tương tác nhấp chuột
    window.clickZone = (idx) => {
        const d = zoneDataMap[idx];
        if(!d) return;

        document.getElementById('p-name').innerText = d.name;

        const tagEl = document.getElementById('p-tag');
        if(d.status === 'locked'){
            tagEl.innerText = "⛔ Chưa mở khóa";
            tagEl.className = "panel-tag locked";
        } else if(d.status === 'current'){
            tagEl.innerText = "🚩 Đang ở đây";
            tagEl.className = "panel-tag current";
        } else {
            tagEl.innerText = "✨ Có thể đến";
            tagEl.className = "panel-tag open";
        }

        document.getElementById('p-weather').innerText = d.weather;
        document.getElementById('p-crowd').innerText = d.crowd;
        document.getElementById('p-facility').innerText = d.facility;
        document.getElementById('p-trend').innerText = d.trend;
        document.getElementById('p-rare').innerText = d.rare;
    };

    const currentIdx = zoneDataMap.findIndex(d => d.status === 'current');
    if(currentIdx >= 0) window.clickZone(currentIdx);


    // 4. Logic điều hướng nhanh
    const navs = getVal('d-nav').split('|');
    let navHtml = "";
    navs.forEach(n => {
        if(n && n.length > 1) {
            navHtml += `<div class="chip" onclick="window.sendNav('${n}')">${n}</div>`;
        }
    });
    document.getElementById('ui-navs').innerHTML = navHtml;

    window.sendNav = (dest) => {
        if(window.triggerSlash) window.triggerSlash(`/send Đến${dest}`);
        else console.log("Move to", dest);
    };

})();
</script>
</body>
</html>
