 <script>
 (function(){
     // HELPER: Lấy dữ liệu an toàn
     const getVal = (id) => document.getElementById(id) ? document.getElementById(id).innerText : "";

     // 1. Điền thông tin cơ bản
     const targetRaw = getVal('d-target').split('|'); // Name|Gender|Sub
     const rateRaw = getVal('d-rate').trim();

     document.getElementById('ui-name').innerText = targetRaw[0] || "Target";
     document.getElementById('ui-sub').innerText = targetRaw[2] || "";

     // Avatar
     const av = document.getElementById('ui-avatar');
     const gender = (targetRaw[1] || "").trim().toLowerCase();
     av.innerText = gender === 'f' || gender === 'female' ? '♀' : '♂';
     av.className = `target-avatar ${gender === 'f' || gender === 'female' ? 'f' : 'm'}`;

     // 2. Thanh tiến độ
     const rateNum = parseInt(rateRaw) || 0;
     setTimeout(()=>{
         document.getElementById('ui-rate-bar').style.width = rateNum + "%";
     }, 100);
     document.getElementById('ui-rate-num').innerText = rateNum + "%";

     // 3. Xây dựng biểu đồ (Chart)
     // Định dạng: Name|Val|Class#Name|Val|Class...
     const chartData = getVal('d-chart').split('#');
     let chartHTML = "";
     chartData.forEach(item => {
         const p = item.split('|');
         if(p.length < 2) return;
         const name = p[0];
         const val = p[1];
         const clz = p[2] || "mid";
         chartHTML += `
         <div class="stat-item">
             <div class="stat-top">
                 <span class="stat-name">${name}</span>
                 <span class="stat-val">${val}%</span>
             </div>
             <div class="stat-bar"><div class="stat-fill ${clz}" style="width:${val}%;"></div></div>
         </div>`;
     });
     document.getElementById('ui-stats').innerHTML = chartHTML;

     // 4. Lời khuyên (Advice)
     document.getElementById('ui-advice').innerHTML = getVal('d-advice');

     // 5. Nút hành động (Actions)
     // Định dạng: Cmd|Title|Desc|RateStr
     const actionsObj = document.getElementById('ui-actions');
     let actsHTML = "";
     // Thay thế biểu tượng quốc phong
     const icons = ["🍶", "🍵", "💌"];

     for(let i=1; i<=4; i++){
         const split = getVal('d-act'+i).split('|');
         if(split.length < 2) continue;

         const cmd = split[0];
         const title = split[1];
         const desc = split[2];
         const rateStr = split[3];
         const isRisky = i === 4;
         const icon = isRisky ? "🌪️" : (icons[i-1] || "👉");

         actsHTML += `
         <button class="option-btn ${isRisky?'risky':''}" data-action="${cmd}">
             <span class="opt-icon">${icon}</span>
             <div class="opt-info">
                 <div class="opt-name">${title}</div>
                 <div class="opt-desc">${desc}</div>
                 <div class="opt-rate ${isRisky?'warn':''}">Đánh giá thành công: ${rateStr}</div>
             </div>
         </button>
         `;
     }
     actionsObj.innerHTML = actsHTML;

     // 6. Ràng buộc nhấp chuột
     actionsObj.addEventListener('click', (e)=>{
         const btn = e.target.closest('.option-btn');
         if(btn && btn.dataset.action){
              if(window.triggerSlash) window.triggerSlash(`/send ${btn.dataset.action}`);
              else console.log("Action:", btn.dataset.action);
         }
     });

 })();
 </script>
 </body>
 </html>
 ```

