 }

 .bottom-note {
     text-align:center; font-size:10px; color:#aaa; margin-top:8px;
     /* Thay đổi font chữ gợi ý */
     font-family: 'Charm', cursive; font-weight: 700; opacity:0.8;
     flex-shrink: 0;
 }
 </style>

 <script>
 (function(){
     const $ = i => document.getElementById(i);
     const rd = i => ( $(i) ? $(i).innerText.trim() : '' );

     // 1. Thiết lập dữ liệu phần đầu
     const loc = rd('meta-loc');
     const cnt = rd('meta-cnt');
     $('ui-loc').innerText = loc || 'Khu vực chưa rõ';
     $('ui-cnt').innerText = cnt || '0';

     // 2. Bộ phân tích
     function parseNPC(raw) {
         if(!raw || raw.length < 3) return null;
         // Cấu trúc dữ liệu: Name|Type|Tag|Rate|Gender|Age|Height|Figure|Job|Pos|ExKey|ExVal|Status|Action
         const p = raw.split('|');
         return {
             name: p[0]||'Vô danh', type: p[1]||'mob', tag: p[2]||'Người qua đường',
             rate: parseInt(p[3]||'0'), sex: p[4]||'female', age: p[5]||'?',
             h: p[6]||'?', fig: p[7]||'-', job: p[8]||'Thất nghiệp',
             pos: p[9]||'Gần đây', k: p[10]||'Ghi chú', v: p[11]||'Không',
             st: p[12]||'Bình thường', act: p[13]||'Bắt chuyện'
         };
     }

     // 3. Render
     let html = '';
     const slots = ['d-s1','d-s2','d-s3','d-s4','d-s5'];
     slots.forEach(id => {
         const data = parseNPC(rd(id));
         if(!data) return;

         const isKey = data.type === 'key';
         const cClass = isKey ? 'npc-card style-key' : 'npc-card';
         const tClass = isKey ? 't-key' : 't-norm';
         const sexIcon = data.sex === 'female' ? '🌸' : '🎋';

         const rateW = Math.min(100, Math.max(0, data.rate));

         html += `
         <div class="${cClass}">
             <div class="card-left">
                 <div class="avatar ${data.sex}">${sexIcon}</div>
                 <div class="rate-box">
                     <div class="rate-circle"><div class="rate-in" style="width:${rateW}%"></div></div>
                     <span class="rate-txt">Duyên:${data.rate}%</span>
                 </div>
             </div>
             <div class="card-right">
                 <div class="row-head">
                     <span class="name">${data.name}</span>
                     <span class="tag ${tClass}">${data.tag}</span>
                 </div>
                 <div class="info-grid">
                     <div class="i-item"><span class="i-lbl">Tuổi</span><span class="i-val">${data.age}</span></div>
                     <div class="i-item"><span class="i-lbl">Dáng</span><span class="i-val">${data.h}/${data.fig}</span></div>
                     <div class="i-item"><span class="i-lbl">Thân phận</span><span class="i-val">${data.job}</span></div>
                 </div>
                 <div class="desc-box">
                     <div><span class="hl">📌 ${data.k}:</span> ${data.v}</div>
                     <div style="margin-top:2px;color:#999">📍 ${data.pos} | Trạng thái: ${data.st}</div>
                 </div>
                 <div class="act-area">
                     <button class="btn" data-act="${data.act}">${data.act}</button>
                     ${isKey ? `<button class="btn capture" data-act="Bắt giữ ${data.name}">❤ Kết Ước ❤</button>` : ''}
                 </div>
             </div>
         </div>
         `;
     });

     if(html) $('npc-container').innerHTML = html;

     // 4. Ủy quyền sự kiện
     $('npc-container').onclick = function(e) {
         const b = e.target.closest('button');
         if(b && b.dataset.act) {
             const cmd = `/send ${b.dataset.act}`;
             if(window.triggerSlash) window.triggerSlash(cmd);
             else console.log(cmd);
         }
     }
 })();
 </script>
 </body>
 </html>
 ```

