 <script>
 (function(){
     const getVal = (id) => document.getElementById(id) ? document.getElementById(id).innerText.trim() : "";

     // 1. Khởi tạo
     document.getElementById('ui-user').innerText = (getVal('d-user').substring(0,1) || "Ta");

     // 2. Phân tích Bonds
     const bondsRaw = getVal('d-bonds').split('#');
     document.getElementById('ui-count').innerText = "Tổng kết: " + ["Không","Nhất","Nhị","Tam","Tứ","Ngũ","Lục","Thất","Bát","Cửu"][bondsRaw.length] || bondsRaw.length;
     const bondsContainer = document.getElementById('ui-bonds');
     const bondsData = [];
     let html = "";

     const items = bondsRaw.filter(s => s.length > 2);
     const radius = 90; // Bán kính mở rộng phù hợp vòng tròn lớn

     items.forEach((str, i) => {
         const p = str.split('|');
         const data = {
             id: i,
             name: p[0],
             title: p[1],
             val: p[2],
             type: p[3] || 'friend',
             desc: p[4]
         };
         bondsData.push(data);

         // Logic phân bố
         const angle = -90 + (360 / items.length) * i;
         const rad = angle * (Math.PI / 180);
         const topOfs = Math.sin(rad) * radius;
         const leftOfs = Math.cos(rad) * radius;

         html += `
         <div class="sat-node type-${data.type}"
              style="top:calc(50% + ${topOfs}px); left:calc(50% + ${leftOfs}px); animation: float-y 4s ease-in-out ${i*0.8}s infinite;"
              onclick="window.selBond(${i}, this)">
              ${data.name.substring(0,1)}
              <div class="sat-name">${data.name}</div>
         </div>`;
     });
     bondsContainer.innerHTML = html;

     // 3. Nhấp xem chi tiết
     const detailCard = document.getElementById('ui-detail-card');
     window.selBond = (idx, el) => {
         document.querySelectorAll('.sat-node').forEach(e => e.classList.remove('active'));
         el.classList.add('active');

         const d = bondsData[idx];
         document.getElementById('dc-name').innerText = d.name;

         // Ánh xạ tiếng Việt loại hình
         const typeMap = {'love': 'Hồng Nhan', 'friend': 'Chí Hữu', 'hate': 'Túc Địch', 'archi': 'Quân Thần'};
         document.getElementById('dc-type').innerText = (typeMap[d.type] || d.title).toUpperCase();

         document.getElementById('dc-val').innerText = d.val + "%";
         document.getElementById('dc-desc').innerText = d.desc;

         // Màu sắc
         const cMap = {'love': '#e91e63', 'friend': '#9c27b0', 'hate': '#424242', 'archi': '#2196f3'};
         document.getElementById('dc-bar').style.background = cMap[d.type] || '#D4AF37';
         setTimeout(()=> document.getElementById('dc-bar').style.width = d.val + "%", 50);
     };

     // 4. Nhật ký
     const logsRaw = getVal('d-logs').split('#');
     let logHtml = "";
     logsRaw.forEach(l => {
         const p = l.split('|');
         if(p.length >= 2){
             logHtml += `<div class="log-item"><span class="log-who">${p[0]}</span><span>${p[1]}</span></div>`;
         }
     });
     document.getElementById('ui-logs').innerHTML = logHtml || '<div style="text-align:center;font-size:10px;color:#999;font-style:italic">Tạm không có vãng sự...</div>';

 })();
 </script>
 </body>
 </html>
