             <span class="sh-icon">☯</span>
             <span class="sh-title">Luật Lệ Nhân Quả</span>
         </div>
         <div class="sh-right" id="ui-id">SIM-000</div>
     </div>

     <div class="scroll-content">

         <div class="info-card trigger-card">
             <div class="ic-header">
                 <span class="ic-title">Thiên Cơ · Kích Hoạt</span>
                 <span class="ic-sub">EVENT TRIGGER</span>
             </div>
             <div class="trig-main" id="ui-trig-text">Đang suy diễn...</div>
             <div class="trig-stamp" id="ui-trig-lvl">LV.0</div>
         </div>

