                 <span class="ic-sub">MACRO SHIFT</span>
             </div>
             <div class="fly-content">
                 <div class="compass-box">
                     <div class="compass-ring">
                         <div class="compass-val" id="ui-fly-ring"></div>
                         <span class="cp-center" id="ui-fly-rate">0%</span>
                     </div>
                 </div>
                 <div class="fly-text-area">
                     <span class="fly-head" id="ui-fly-target">---</span>
