 <script>
 (function(){
     const get = (id) => document.getElementById(id) ? document.getElementById(id).innerHTML.trim() : "";
     const strip = (s) => s.replace(/<[^>]*>/g, '');

     // 0. ID
     document.getElementById('ui-id').innerText = get('d-id');

     // 1. Trigger (Thiên cơ)
     const tRaw = strip(get('d-trig')).split('|');
     document.getElementById('ui-trig-text').innerText = tRaw[0] || "Tĩnh quan kỳ biến...";
     const tLvl = (tRaw[1] || "Normal").trim();
     const tBadge = document.getElementById('ui-trig-lvl');
     // Dịch các mức độ
     tBadge.innerText = tLvl === 'Critical' ? 'Đại Hung' : (tLvl === 'High' ? 'Hung' : 'Bình');
     tBadge.className = `trig-stamp lvl-${tLvl}`;

     // 2. Ripples (Nhân mưu)
     const rRaw = strip(get('d-rip')).split('#');
     let rHtml = "";
     rRaw.forEach(x => {
         const p = x.split('|');
         if(p.length >= 2){
             rHtml += `
             <div class="rip-item">
                 <div class="rip-seal">${p[0].substring(0,1)}</div>
                 <div class="rip-detail">
                     <div class="rip-name">${p[0]}</div>
                     <div class="rip-act">${p[1]}</div>
                 </div>
                 <div class="rip-delta">${p[2]||''}</div>
             </div>`;
         }
     });
     document.getElementById('ui-ripples').innerHTML = rHtml;

     // 3. Butterfly (Đại thế)
     const bRaw = strip(get('d-fly')).split('|');
     const rate = parseFloat(bRaw[0]||0);
     document.getElementById('ui-fly-rate').innerText = rate + "%";
     document.getElementById('ui-fly-ring').style.transform = `rotate(${rate * 3.6}deg)`;
     document.getElementById('ui-fly-target').innerText = bRaw[1] ? `[Biến số: ${bRaw[1]}]` : "";
     document.getElementById('ui-fly-desc').innerText = bRaw[2] || "";

     // 4. Forecast (Mệnh số)
     const fRaw = strip(get('d-cast')).split('#');
     let fHtml = "";
     fRaw.forEach(x => {
         const p = x.split('|');
         if(p.length >= 2){
             const prob = parseInt(p[1]) || 0;
             const type = (p[2]||'neutral').trim();
             fHtml += `
             <div class="fc-row t-${type}">
                 <div class="fc-top"><span class="fc-label">${p[0]}</span><span class="fc-pct">${prob}%</span></div>
                 <div class="fc-bar-bg"><div class="fc-bar-fg" style="width:${prob}%"></div></div>
                 <div class="fc-info">${p[3]||''}</div>
             </div>`;
         }
     });
     document.getElementById('ui-forecast').innerHTML = fHtml;

 })();
 </script>
