 }

 body { margin: 0; padding: 0; display: flex; justify-content: center; background: transparent; font-family: var(--font-std); color: var(--ny-dark); }
 * { box-sizing: border-box; user-select: none; }

 /* Container hộp gấm chính */
 .ach-box {
     width: 100%; max-width: 420px;
     margin: 20px auto;
     background-color: var(--ny-paper);
     background-image: var(--ny-bg-pattern);
