     cursor: pointer;
     position: relative;
     transition: 0.3s;
 }
 .nav-btn.active { color: var(--ny-gold-light); transform: translateY(2px); background: rgba(0,0,0,0.2); border-radius: 0 0 8px 8px; }
 .nav-btn.active::after { content: '◈'; display: block; position: absolute; bottom: -10px; left: 50%; transform: translateX(-50%); font-size: 10px; color: var(--ny-gold); }

 /* Hiệu ứng chuyển trang */
 .page { display: none; padding: 20px; animation: rollIn 0.5s ease; }
 .page.show { display: block; }
 @keyframes rollIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }

 /* === PAGE 1: Bảng Công Trạng (Mới mở khóa) === */
 .rank-bar {
     display: flex; justify-content: space-between; align-items: baseline;
     margin-bottom: 25px; border-bottom: 1px dotted var(--ny-gold); padding-bottom: 5px;
 }
 .rank-lbl { font-family: var(--font-std); font-size: 12px; color: #555; display: flex; align-items: center; gap: 4px; }
 .rank-lbl::before { content:'♟'; color: var(--ny-red-primary); }
 .rank-val { font-family: var(--font-art); font-size: 20px; color: var(--ny-red-deep); margin-left: 4px; font-weight: 700; }
 .total-pts { font-family: monospace; font-size: 14px; font-weight: 700; color: var(--ny-gold); background: var(--ny-red-deep); padding: 2px 8px; border-radius: 4px; }

 /* Thẻ huy chương cốt lõi - Phong cách thánh chỉ */
 .honor-card {
     position: relative;
     border: 4px double var(--ny-gold); /* Viền vàng đôi */
     background: #fff;
     padding: 20px;
     text-align: center;
     box-shadow: inset 0 0 20px rgba(222,165,75,0.1);
     overflow: hidden;
 }
 /* Trang trí vân mây bốn góc */
 .honor-card::before, .honor-card::after {
     content: '☁'; position: absolute; font-size: 24px; color: var(--ny-gold); opacity: 0.4;
 }
 .honor-card::before { top: -5px; left: 5px; transform: rotate(180deg); }
 .honor-card::after { bottom: -5px; right: 5px; }

 /* Hiệu ứng ruy băng rơi */
 .confetti {
     position: absolute; inset: 0; pointer-events: none; opacity: 0.2;
     background-image: radial-gradient(var(--ny-red-primary) 15%, transparent 16%);
     background-size: 12px 12px; animation: rain 4s linear infinite;
 }
 @keyframes rain { 0% { background-position: 0 0; } 100% { background-position: 0 60px; } }

 .honor-icon { font-size: 56px; margin: 10px 0; display: block; filter: drop-shadow(0 4px 0 rgba(0,0,0,0.1)); }
 .honor-seal {
     display: inline-block; padding: 4px 16px;
     background: var(--ny-red-deep); color: var(--ny-gold-light);
     border-radius: 50px; border: 1px solid var(--ny-gold);
     font-size: 10px; letter-spacing: 2px; text-transform: uppercase; font-weight: bold;
     margin-bottom: 15px; position: relative;
     box-shadow: 0 2px 5px rgba(0,0,0,0.15);
 }
 .honor-title {
     font-family: var(--font-art); font-weight: 700; font-size: 28px; line-height: 1.2;
     color: var(--ny-dark); margin: 0 0 10px 0;
