 <div class="ach-box">
     <div class="ach-nav">
         <div class="nav-btn active" onclick="switchTab('top', this)">🥇 Công Huân Phong Thưởng</div>
         <div class="nav-btn" onclick="switchTab('list', this)">📜 Hãn Thanh Sử Sách</div>
     </div>

     <div id="page-top" class="page show">
         <div class="rank-bar">
             <div class="rank-lbl">Vị giai hiện tại<span class="rank-val" id="ui-rank">?</span></div>
             <div class="total-pts" id="ui-pts">0</div>
         </div>

         <div class="honor-card">
             <div class="confetti"></div>
             <span class="honor-icon">🛡️</span>
             <div><span class="honor-seal" id="ui-rarity">COMMON</span></div>
             <h2 class="honor-title" id="ui-title">Chưa lập công danh</h2>
             <div class="honor-desc" id="ui-desc">Đợi chờ kiến công lập nghiệp...</div>
         </div>
     </div>

     <div id="page-list" class="page">
         <div class="list-container" id="ui-list">
             <div style="text-align:center; padding:30px; color:#bbb; font-size:12px;">Tạm không có sử liệu ghi chép</div>
         </div>
     </div>
 </div>

 <script>
 (function(){
     const $ = i => document.getElementById(i);
     const get = i => $(i) ? $(i).innerText.trim() : "";

     // 1. Phân tích dữ liệu
     const rankStr = get('raw-rank') || "Bố Y";
     const ptsStr = get('raw-pts') || "0";
     const toastArr = get('raw-toast').split('|'); // [Name, Rarity, IconChar]
     const descStr = get('raw-desc') || "Đợi kiến công lập nghiệp";
     const listRaw = get('raw-list');

     const tName = toastArr[0] || "Thành tựu chưa mở khóa";
     const tRarity = toastArr[1] || "Common"; // Common, Rare, Epic, Legendary
     // Ánh xạ độ hiếm tiếng Anh sang từ Hán Việt nhã nhặn
     const rareMap = {
         'Common': 'Phàm Phẩm', 'Rare': 'Trân Kỳ', 'Epic': 'Tuyệt Thế', 'Legendary': 'Truyền Thế Thần Thoại'
         ,'Bronze':'Hoàng Đồng','Silver':'Bạch Ngân','Gold':'Hoàng Kim','Platinum':'Bạch Kim'
     };
     const tIcon = toastArr[2] || "🐲";

     // 2. Điền Page 1
     $('ui-rank').innerText = rankStr;
     $('ui-pts').innerText = ptsStr + " Công Tích"; // Thêm hậu tố
     $('ui-title').innerText = tName;
     $('ui-rarity').innerText = rareMap[tRarity] || tRarity;
     $('ui-desc').innerText = descStr;
     document.querySelector('.honor-icon').innerText = tIcon;

     // Điều chỉnh động màu viền thẻ (Ghi đè biến CSS)
     const card = document.querySelector('.honor-card');
     const seal = document.querySelector('.honor-seal');
     let color = "#A8A29E"; // Default
     if(tRarity==='Rare'||tRarity==='Silver') color = "#3B82F6";
     if(tRarity==='Epic'||tRarity==='Gold') color = "#D368FA";
     if(tRarity==='Legendary'||tRarity==='Platinum') color = "#DEA54B"; // Gold

     seal.style.backgroundColor = color;
     seal.style.borderColor = color;
     if(tRarity === 'Legendary' || tRarity === 'Platinum') {
         card.style.borderColor = color;
         card.style.boxShadow = `inset 0 0 30px ${color}33`; // Tăng phát sáng bên trong
     }

     // 3. Điền Page 2
     if(listRaw) {
         const items = listRaw.split('#');
         let html = "";
         items.forEach(line => {
             const p = line.split('|');
             if(p.length < 2) return;
             const n = p[0];
             const r = p[1] || 'Common';
             const icon = p[2] || '📜';
             const cnR = rareMap[r] || r;

             html += `
             <div class="log-item ${r}">
                 <div class="log-ico-wrap">${icon}</div>
                 <div class="log-content">
                     <span class="log-name">${n}</span>
                     <span class="log-badge">${cnR}</span>
                 </div>
             </div>`;
         });
         $('ui-list').innerHTML = html;
     }

     // 4. Chuyển Tab
     window.switchTab = (tid, btn) => {
         document.querySelectorAll('.page').forEach(el => el.classList.remove('show'));
         document.querySelectorAll('.nav-btn').forEach(el => el.classList.remove('active'));
         $('page-'+tid).classList.add('show');
         btn.classList.add('active');
     };
 })();
 </script>
 </body>
 </html>
