         box-shadow: 0 4px 10px rgba(155, 40, 40, 0.3); transition: 0.2s;
         display: flex; align-items: center; gap: 4px;
     }
     .btn-exec::after { content: '🖐️'; font-size: 12px; }
     .btn-exec:hover { background: var(--ny-red-primary); transform: translateY(-1px); }
     .btn-exec:active { transform: scale(0.95); }
 </style>
 </head>
 <body>
 <div class="terminal-window">
     <header>
         <div class="header-title">Kiểm Tra Hành Trang: $1</div>
         <div class="header-id">Cung Hỷ Phát Tài</div>
     </header>
     <div class="main-grid">
         <div class="equip-column" id="eq-box"></div>
         <div class="items-column" id="it-box"></div>
     </div>
     <footer>
         <input type="text" id="steal-input" placeholder="Ưng cái nào thì chọn cái đó...">
         <button class="btn-exec" onclick="fireSteal()">Thuận Tay Dắt Dê</button>
     </footer>
 </div>

 <script>
 (function(){
     // Chú ý điểm tiêm dữ liệu:
     // $3 Tương ứng dữ liệu trang bị: Đầu|Trên|Dưới|Trong|Chân|Trang sức A|Trang sức B
     // $4 Tương ứng dữ liệu đạo cụ: Loại:Tên:Số:Sao#...
     const raw_eq = `$3`;
     const raw_it = `$4`;

     // Sửa lỗi hiển thị mặc định khi regex chưa thay thế
     const e_raw = (raw_eq.includes('$') || !raw_eq) ? [] : raw_eq.split('|');
     const i_raw = (raw_it.includes('$') || !raw_it) ? [] : raw_it.split('#');

     // Tên các ô trang bị (Việt hóa phong cách cổ trang)
     const slotNames = ['Mũ Nón','Áo Trên','Hạ Y','Nội Y','Giày Hài','Phụ Kiện·1','Phụ Kiện·2'];

     // Render trang bị
     document.getElementById('eq-box').innerHTML = slotNames.map((name, i) => {
         const val = e_raw[i] || 'Trống';
         const isNone = val === '无' || val === '空缺' || val === '' || val === 'Không' || val === 'Trống';
         return `<div class="eq-slot" onclick="sel('${isNone?'':val}')">
             <span class="eq-label">${name}</span>
             <span class="eq-name ${isNone?'none':''}">${isNone ? 'Không' : val}</span>
         </div>`;
     }).join('');

     // Render đạo cụ
     if(i_raw.length === 0 || (i_raw.length===1 && !i_raw[0])){
          document.getElementById('it-box').innerHTML = `<div style="text-align:center; padding: 40px; color:#ccc; font-size:14px;">Trống Rỗng<br>Phú Quý Tại Thiên </div>`;
     } else {
         document.getElementById('it-box').innerHTML = i_raw.map(row => {
             const parts = row.split(':');
             if(parts.length < 2) return '';
             const [cat, name, num, star] = parts;

             const sCls = 's' + (star || 3);
             const stars = '★'.repeat(star || 3);
             return `
             <div class="item-row" onclick="sel('${name}')">
                 <span class="item-class">${cat}</span>
                 <span class="item-main">${name}</span>
                 <div class="item-meta">
                     <span class="item-star ${sCls}">${stars}</span>
                     <span class="item-count">×${num}</span>
                 </div>
             </div>`;
         }).join('');
     }

     window.sel = (n) => {
         if(n && n !== '无' && n !== '空缺' && n !== 'Không' && n !== 'Trống') {
             document.getElementById('steal-input').value = n;
             // Hoạt ảnh phản hồi nhấp chuột đơn giản
             const inp = document.getElementById('steal-input');
             inp.style.transform = 'scale(1.05)';
             setTimeout(()=>inp.style.transform = 'scale(1)', 100);
         }
     };

     window.fireSteal = () => {
         const target = document.getElementById('steal-input').value;
         if(!target) return;
         // Giữ nguyên logic chức năng gốc nhưng dịch lệnh gửi đi
         const finalMsg = `Sử dụng chế độ điều chỉnh thế giới Trộm cắp ${target}`;

         // Thử gửi đến khung nhập liệu tửu quán
         try {
             const tArea = parent.document.getElementById('send_textarea') || parent.document.querySelector('textarea');
             const sBtn = parent.document.getElementById('send_but') || parent.document.querySelector('#send_but');
             if (tArea && sBtn) {
                 tArea.value = finalMsg;
                 tArea.dispatchEvent(new Event('input', { bubbles: true }));
                 setTimeout(() => { sBtn.click(); }, 100);
             } else {
                 console.log("Không tìm thấy giao diện gửi bên ngoài: " + finalMsg);
             }
         } catch(e) {
             console.error(e);
         }
     };
 })();
 </script>
 </body>
 </html>
 ```

