     window.sendCmd = function(d){
         const c = `/send (Lệnh hệ thống) ${d} [Tham số vị trí bổ sung:${curLoc}]|/trigger`;
         if(window.triggerSlash) window.triggerSlash(c);
         else console.log(c);
     };

     if(raw && !raw.startsWith('$')){
         const l = document.getElementById('list-inject');
         l.innerHTML = '';
         const es = raw.split('#');

         es.forEach(e => {
             const ps = e.split('|').map(s=>s.trim());
             if(ps.length < 7) return;
             const [n, g, r, j, lo, b, st] = ps;

             // Logic màu xếp hạng
             let rClass = 'bg-B';
             if(r.includes('SSS') || r.includes('SS')) rClass = 'bg-SSS';
             else if(r.includes('S')) rClass = 'bg-S';
             else if(r.includes('A')) rClass = 'bg-A';

             // Rank viết tắt (S/A/B)
             const rShort = r.replace(/[^SABC]/g,'').substr(0,2);

             l.innerHTML += `
             <div class="beauty-card" onclick="sendCmd('Khóa mục tiêu: ${n} (Đến ${lo})')">
                 <div class="bc-left">
                     <div class="rank-badge ${rClass}">${rShort}</div>
