  <body>

  <div id="raw-pt" style="display:none;">$1</div>
  <div id="raw-ls" style="display:none;">$2</div>

  <div class="edict-container">
      <div class="deco-top-bar"></div>

      <div class="header-section">
          <h1 class="title-main">Thiên Đạo Chiếu Lệnh</h1>
          <div class="sub-title">HEAVENLY·MANDATE</div>
          <div class="merit-tag">
              <span class="mt-label">Điểm Số</span>
              <span class="mt-val" id="ui-pt">--</span>
          </div>
      </div>

      <div class="filter-rail">
          <div class="f-btn active" onclick="ft('ALL',this)">Tất Cả</div>
          <div class="f-btn" onclick="ft('MAIN',this)">Thiên Mệnh</div>
          <div class="f-btn" onclick="ft('WEEKLY',this)">Luân Hồi</div>
          <div class="f-btn" onclick="ft('DAILY',this)">Trần Thế</div>
      </div>

      <div class="list-viewport" id="list-core">
          <div style="text-align:center; padding: 60px 0; color:#BCAAA4;">
              <div style="font-size:32px; margin-bottom:5px; opacity:0.5;">🎴</div>
              <span style="font-size:12px; letter-spacing:1px;">Đang đánh thức linh thức...</span>
          </div>
      </div>

      <div class="claim-all-floater">
          <button class="btn-claim" onclick="sc('Gửi tất cả nhiệm vụ')">Nhất Kiện Phục Mệnh</button>
      </div>

      <div class="deco-btm-bar"><div class="deco-gem"></div></div>
  </div>

  <script>
  (function(){
      const $ = i => document.getElementById(i);
      const rPt = $('raw-pt')?.innerText.trim() || '0';
      const rLs = $('raw-ls')?.innerText.trim() || '';

      $('ui-pt').innerText = rPt;

      window.sc = c => {
          const m = `/send (Lệnh hệ thống) ${c}|/trigger`;
          if(window.triggerSlash) window.triggerSlash(m);
          else console.log(m);
      };

      window.ft = (kp, el) => {
          document.querySelectorAll('.f-btn').forEach(b => b.classList.remove('active'));
          el.classList.add('active');
          document.querySelectorAll('.task-scroll').forEach(c => {
              const show = kp==='ALL' || c.classList.contains('f-'+kp);
              c.style.display = show ? 'block' : 'none';
          });
      };

      const pr = j => {
          try{
              const o = JSON.parse(j);
              let h = '';
              if(o.Pt) h+=`<span class="gold-txt">❖ ${o.Pt}</span>`;
              if(o.Item) h+=`<span class="item-txt">🎁 ${o.Item}</span>`;
              return h;
          }catch(e){return '';}
      };

      if(rLs){
          const con = $('list-core');
          con.innerHTML = '';
          const lines = rLs.split('#');

          lines.forEach((l, idx) => {
              const p = l.split('|').map(x=>x.trim());
              if(p.length < 6) return;

              const [type, st, tit, desc, rew, prog] = p; // MAIN/WEEKLY/DAILY, ACTIVE/DONE...

              // Cập nhật Regex để bắt "Cấm chế/Hạn chế" trong tiếng Việt
              const banM = desc.match(/(?:Cấm chế|Hạn chế|Restriction|禁制)[:：]([^;。]+)/i);
              const banT = banM ? banM[1] : '';
              const mainT = desc.replace(/(?:Cấm chế|Hạn chế|Restriction|禁制)[:：][^;。]+[;。]?/gi, '');

              let pct = 0;
              try { pct = Math.min(100, (parseFloat(prog.split('/')[0])/parseFloat(prog.split('/')[1])*100)); }catch(e){}
              if(st === 'DONE') pct = 100;

              const div = document.createElement('div');
              div.className = `task-scroll f-${type} tk-${st}`; // Ở đây f-type dùng để lọc
              div.style.animationDelay = `${idx * 0.1}s`;

              const wtm = st==='DONE' ? 'Đã Xong' : '';
              const btnT = st==='DONE' ? 'Hoàn Tất' : 'Thực Hiện';

              // Ánh xạ tên loại hình
              let typeName = 'Chưa Rõ';
              if(type === 'MAIN') typeName = 'Thiên Mệnh';
              else if(type === 'WEEKLY') typeName = 'Luân Hồi';
              else if(type === 'DAILY') typeName = 'Trần Thế';

              div.innerHTML = `
                  ${wtm ? `<div class="watermark">${wtm}</div>` : ''}
                  <div class="tk-inner">
                      <div class="tk-header">
                          <div class="tk-tit">${tit}</div>
                          <div class="tk-badge tk-type-${type}">${typeName}</div>
                      </div>

                      <div class="tk-desc-box">
                          ${banT ? `<div class="ban-row">🚫 Cấm chế：${banT}</div>` : ''}
                          ${mainT}
                      </div>

                      <div class="prog-track"><div class="prog-bar" style="width:${pct}%"></div></div>

                      <div class="tk-footer">
                          <div class="rew-box">${pr(rew)}</div>
                          <button class="tk-act-btn" onclick="sc('Thực hiện: ${tit}')">${btnT}</button>
                      </div>
                  </div>
              `;
              con.appendChild(div);
          });
      }
  })();
  </script>
  </body>
  </html>
 ```

