 <body>

 <div id="v-pt" style="display:none;">$1</div>
 <div id="v-json" style="display:none;">$2</div>

 <div class="royal-scroll">
     <div class="header-roof">
         <div class="header-pattern"></div>
         <div class="title-plaque">Vạn Ứng Bảo Các</div>
         <div class="money-pouch">
             <div class="coin-icon">💰</div>
             <div class="pt-label">Điểm</div>
             <div class="pt-val" id="ui-pt">----</div>
         </div>
     </div>

     <div class="tassel-l"></div> <div class="tassel-r"></div>

     <div class="shelf-tabs">
         <div class="tab-btn active" onclick="switchShelf('General', this)">Bách Hóa Thông Thương</div>
         <div class="tab-btn" onclick="switchShelf('Limited', this)">Kỳ Trân Hạn Giờ</div>
         <div class="tab-btn" onclick="switchShelf('Erotic', this)">Hồng Phấn Bí Bảo</div>
     </div>

     <div class="shelf-list" id="shelf-core">
         <div style="padding: 60px 0; text-align: center; color: #aaa;">
             <div style="font-size: 40px; margin-bottom: 10px; opacity: 0.3;">📦</div>
             Chưởng quầy đang kiểm hàng...
         </div>
     </div>

     <div class="footer-seal">
         <span class="seal-txt">Ngự Mã Giám Chế · Thành Tín Vi Bản</span>
     </div>
 </div>

 <script>
 (function(){
     // 1. Phân tích dữ liệu
     const $ = i => document.getElementById(i);
     const rawPt = $('v-pt')?.innerText.trim() || '0';
     const rawData = $('v-json')?.innerText.trim() || '{}';

     let userBalance = parseInt(rawPt) || 0;
     let inventory = {};

     $('ui-pt').innerText = userBalance.toLocaleString(); // Thêm dấu phân cách hàng nghìn

     try {
         inventory = JSON.parse(rawData);
     } catch(e) { console.error('Shop Data Parse Fail'); }

     // 2. Gửi lệnh mua
     window.buyItem = (name, cost) => {
         const cmd = `/send (Lệnh hệ thống) Người chơi xin mua: "${name}" (Trừ ${cost}Pt)|/trigger`; // Lệnh kép
         if(window.triggerSlash) window.triggerSlash(cmd); // Tương thích tửu quán
         else console.log("Sent:", cmd);
     };

     // 3. Chuyển đổi và render kệ hàng
     window.switchShelf = (cat, btn) => {
         // Cập nhật Tab
         document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
         btn.classList.add('active');

         // Render nội dung
         const container = $('shelf-core');
         container.innerHTML = '';

         const items = inventory[cat] || [];

         if(items.length === 0) {
             container.innerHTML = `<div style="padding:60px 0;text-align:center;color:#bcaaa4;font-family:var(--font-body)">Quầy này hôm nay đã bán hết</div>`;
             return;
         }

         items.forEach((item, idx) => {
             // Hiệu ứng chậm
             const canAfford = userBalance >= item.p;
             const card = document.createElement('div');
             card.className = `ware-card role-${cat} ${canAfford ? '' : 'poor'}`;
             card.style.animation = `fadeSlideEn 0.4s ease forwards ${idx * 0.05}s`;
             card.style.opacity = '0'; // khởi tạo ẩn

             // Văn bản nút động
             const btnTxt = canAfford ? 'Mua Vào' : 'Thiếu Tiền';

             card.innerHTML = `
                 <div class="w-icon">${item.i}</div>
                 <div class="w-info">
                     <div class="w-name">${item.n}</div>
                     <div class="w-desc">${item.d}</div>
                 </div>
                 <div class="w-action">
                     <div class="w-cost">${item.p}</div>
                     <button class="w-btn" onclick="buyItem('${item.n}', ${item.p})">${btnTxt}</button>
                 </div>
             `;
             container.appendChild(card);
         });
     };

     // 4. Chèn style dùng cho hiệu ứng danh sách
     const styleSheet = document.createElement("style");
     styleSheet.innerText = `@keyframes fadeSlideEn { from { opacity:0; transform:translateY(10px); } to { opacity:1; transform:translateY(0); } }`;
     document.head.appendChild(styleSheet);

     // 5. Tải ban đầu
     const initTab = document.querySelector('.tab-btn');
     if(initTab && inventory) window.switchShelf('General', initTab);

 })();
 </script>
 </body>
 </html>
 ```
